# Preprocessing functions
def preprocess(text):
    text = text.lower()
    text = re.sub(f'[{string.punctuation}]', ' ', text)
    tokens = text.split()
    stop_words = set(['the', 'and', 'of', 'to', 'a', 'in', 'is', 'it', 'this', 'that', 'for', 'on', 'as', 'by', 'an'])
    tokens = [word for word in tokens if word not in stop_words]
    return tokens

def stem(word):
    if word.endswith('ing'):
        return word[:-3]
    elif word.endswith('ed'):
        return word[:-2]
    elif word.endswith('s'):
        return word[:-1]
    else:
        return word

def tokenize(text):
    return [stem(word) for word in preprocess(text)]

